let inputPrompt = $input.first().json.output;

// 1. Remove line breaks
let cleanPrompt = inputPrompt.split(/\r?\n/).join(" ");

// 2. Remove Markdown (** and * bullets)
cleanPrompt = cleanPrompt.replace(/\*\*/g, "").replace(/\*/g, "");

// 3. Replace double quotes with single quotes
cleanPrompt = cleanPrompt.replace(/"/g, "'");

// 4. Build n8n-compatible return
return [
  {
    json: {
      prompt: cleanPrompt
    }
  }
];

return items.map(item => {
    const responseData = item.json;

    if (responseData?.candidates?.length > 0) {
        const parts = responseData.candidates[0].content.parts;

        // look for inlineData (image) in parts[0] or parts[1]
        const imagePart = parts.find(p => p.inlineData);

        if (imagePart) {
            return {
                json: {
                    imageBase64: imagePart.inlineData.data
                }
            };
        }
    }

    // if no image found
    return { json: {} };
});
